// Next.js (React Framework) · 15.2.0
// Caso: Crear base de datos | Nivel: Básico | Categoría: Base de datos
// IndexedDB (navegador) - ejemplo minimalista.
// DB: demo_db | stores: users, orders
// Nota: IndexedDB NO es SQL. Es key-value con índices. JOIN se hace en memoria.

function openDb(version = 1) {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open('demo_db', version);
    req.onupgradeneeded = () => {
      const db = req.result;

      if (!db.objectStoreNames.contains('users')) {
        const users = db.createObjectStore('users', { keyPath: 'id', autoIncrement: true });
        users.createIndex('email', 'email', { unique: true });
        users.createIndex('created_at', 'created_at', { unique: false });
      }

      if (!db.objectStoreNames.contains('orders')) {
        const orders = db.createObjectStore('orders', { keyPath: 'id', autoIncrement: true });
        orders.createIndex('user_id', 'user_id', { unique: false });
        orders.createIndex('created_at', 'created_at', { unique: false });
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

function txDone(tx) {
  return new Promise((resolve, reject) => {
    tx.oncomplete = () => resolve(undefined);
    tx.onerror = () => reject(tx.error || new Error('tx error'));
    tx.onabort = () => reject(tx.error || new Error('tx abort'));
  });
}
export async function solve() {
  const db = await openDb(1);
  db.close();
  return 'demo_db listo';
}

