  const rows = orders.map(o => ({
    user_id: o.user_id,
    user_name: byId.get(o.user_id)?.name ?? null,
    order_id: o.id,
    total: o.total,
    created_at: o.created_at,
  }));
  rows.sort((a,b) => String(b.created_at).localeCompare(String(a.created_at)));
