// Paginación: cursor y saltos.
export async function solve(offset = 20, limit = 10) {
  const db = await openDb(1);
  const tx = db.transaction(['users'], 'readonly');
  const store = tx.objectStore('users');
  const out = [];
  let skipped = 0;
  await new Promise((resolve, reject) => {
    const r = store.openCursor();
    r.onsuccess = () => {
      const cur = r.result;
      if (!cur) return resolve(undefined);
      if (skipped < offset) { skipped++; cur.continue(); return; }
      if (out.length >= limit) return resolve(undefined);
      out.push(cur.value);
      cur.continue();
    };
    r.onerror = () => reject(r.error);
  });
  await txDone(tx);
  db.close();
  return out;
}

