// Next.js (React Framework) · 15.2.0
// Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
// Acepta formatos: 12.345.678-5, 12345678-5, 123456785, etc.

function solve(rut) {
  const clean = String(rut).replace(/[.\-\s]/g, '').toUpperCase();
  if (clean.length < 2) return false;

  const body = clean.slice(0, -1);
  const dv = clean.slice(-1);

  if (!/^\d+$/.test(body)) return false;

  let sum = 0;
  let mul = 2;
  for (let i = body.length - 1; i >= 0; i--) {
    sum += Number(body[i]) * mul;
    mul = (mul === 7) ? 2 : (mul + 1);
  }

  const mod = 11 - (sum % 11);
  const dvCalc = (mod === 11) ? '0' : (mod === 10) ? 'K' : String(mod);

  return dv === dvCalc;
}

