// C0667 · BFS/DFS (grafo) (Intermedio, Algoritmos)
// graph: {A:[B,C], B:[D], C:[], D:[]}
function bfs(graph, start){
  const q=[start], seen=new Set([start]), out=[];
  while(q.length){
    const v=q.shift(); out.push(v);
    for(const n of (graph[v]||[])){
      if(!seen.has(n)){ seen.add(n); q.push(n); }
    }
  }
  return out;
}
function dfs(graph, start){
  const seen=new Set(), out=[];
  (function visit(v){
    seen.add(v); out.push(v);
    for(const n of (graph[v]||[])) if(!seen.has(n)) visit(n);
  })(start);
  return out;
}

