// Next.js (React Framework) · 15.2.0
// C0672 · Animación sprite (frame step) (Intermedio, Juegos)
// frame step por tiempo acumulado
function solve(state, dt, fps, frameCount){
  state.acc = (state.acc || 0) + dt;
  const frameTime = 1 / fps;
  while(state.acc >= frameTime){
    state.acc -= frameTime;
    state.frame = ((state.frame || 0) + 1) % frameCount;
  }
  return state.frame || 0;
}

