// C0673 · State machine (menú/juego/pausa) (Intermedio, Juegos)
const State = { MENU:"MENU", PLAY:"PLAY", PAUSE:"PAUSE" };

function transition(state, event){
  switch(state){
    case State.MENU:
      if(event==="start") return State.PLAY;
      return state;
    case State.PLAY:
      if(event==="pause") return State.PAUSE;
      if(event==="quit") return State.MENU;
      return state;
    case State.PAUSE:
      if(event==="resume") return State.PLAY;
      if(event==="quit") return State.MENU;
      return state;
    default:
      return State.MENU;
  }
}

