// C0680 · Uso de teclado (keydown/atajos) (Intermedio, UI/Entrada)
// Next.js: app/page.jsx (Client Component para teclado)
"use client";
import { useEffect } from "react";

export default function Page() {
  useEffect(() => {
    const onKey = (e) => {
      if (e.ctrlKey && e.key.toLowerCase() === "s") { e.preventDefault(); console.log("Ctrl+S"); }
      if (e.key === "Escape") console.log("Escape");
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  return <main style={{ padding: 16 }}>Presiona Ctrl+S / Escape (consola)</main>;
}

